#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int *a = (int*)malloc(N * sizeof(int));
        int *b = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        for (int i = 0; i < M; ++i) scanf("%d", &b[i]);
        int i = 0, j = 0, carry = 0;
        int first = 1;
        while (i < N || j < M || carry) {
            int sum = carry;
            if (i < N) sum += a[i++];
            if (j < M) sum += b[j++];
            int digit = sum % 10;
            carry = sum / 10;
            if (!first) printf(" ");
            printf("%d", digit);
            first = 0;
        }
        printf("\n");
        free(a); free(b);
    }
    return 0;
}

