const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const M = Number(input[idx++]);
  const a = new Array(N);
  const b = new Array(M);
  for (let i = 0; i < N; i++) a[i] = Number(input[idx++]);
  for (let i = 0; i < M; i++) b[i] = Number(input[idx++]);
  let i = 0, j = 0, carry = 0;
  const res = [];
  while (i < N || j < M || carry) {
    let sum = carry;
    if (i < N) sum += a[i++];
    if (j < M) sum += b[j++];
    res.push(sum % 10);
    carry = Math.floor(sum / 10);
  }
  outputs.push(res.join(' '));
